var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"운명과 숙명에 대해, 들어본 적 있나?","JPN":"運命と宿命について、聞いたことはある？","ENG":"Have you heard of fate and destiny?","TWN":"聽說過命運和宿命嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"둘 다 비슷한 말이지만 여기서 말하는 운명과 숙명은 뜻이 조금 달라.","JPN":"どちらも似たような言葉だけど、ここで言う運命と宿命は少し意味合いが違う。","ENG":"While they may sound synonymous, their meanings are a bit different.","TWN":"雖然兩個詞意思接近，但這裡所說的命運和宿命有些不同。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"운명은 세계에서부터 너에게로 비롯되는 것.","JPN":"運命は世界からあなたへ与えられるもの。","ENG":"Fate is thrust upon you by the world...","TWN":"命運是世界會帶給你的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003050","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 숙명은 너 자신이 스스로에게 부여하는 의무지.","JPN":"そして宿命はあなた自身が自らに与える義務。","ENG":"whereas destiny is created by your decisions.","TWN":"但宿命是你自身賦予自己的義務。"},"stage":{"bg":"MAINSTREAM_003024","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"어렵게 생각할 필요 없어, 그냥 취향이라고 생각하면 돼.","JPN":"難しく考える必要はない。ただの好みと思えばいい。","ENG":"Don't let it go over your head. Just think of it as a matter of preference.","TWN":"沒必要想得太複雜，你可以想成是一種喜好就好。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"운명은 엄마가 해 주는 맛없는 영양식이고, 숙명은 네가 먹고 싶지만 몸에는 나쁜 정크 푸드지.","JPN":"運命はお母さんが作ってくれる不味い栄養食で、宿命は君が食べたいけど体には悪いジャンクフードだよ。","ENG":"Fate is like the bland healthy food your mom makes for you... while destiny is like the junk food you'd rather have.","TWN":"命運就像母親為了孩子做的不合口味但卻營養的餐點，宿命則是你自己喜歡吃的垃圾食物。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"굳이 차이가 있다면...... 운명은 피할 수 있지만, 숙명은 그럴 수 없어.","JPN":"あえて違いを言うなら……運命は避けられるけど、宿命は避けられない。","ENG":"If there's a real difference between the two... You can avoid your fate, but not your destiny.","TWN":"非要區分的話……命運可以避開，但宿命沒辦法逃避。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"애초에 숙명은 네 욕망이 만들어내는 거니까.","JPN":"宿命はあなたの欲望が作り出すものだからね。","ENG":"Destiny is forged from your own desires, after all.","TWN":"因為宿命是你的慾望所製造出來的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"누구에게나 정해진 운명과 숙명이 있어.","JPN":"誰にでも決まった運命と宿命がある。","ENG":"Everyone has their own fate and destiny.","TWN":"每個人都有指定的命運和宿命。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그것들을 하나씩 극복해 가면서 강해지고, 성장하게 되지.","JPN":"そして、それらを一つずつ克服していくことで強くなり、成長する。","ENG":"You grow stronger as you overcome them, one at a time.","TWN":"通過克服這些可以變得更強並逐漸成長。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 강해진다고, 성장한다고 해서 그 결과가 자신이 원하던 모습이라는 보장은 없어.","JPN":"でも成長したからといって、その結果が自分が望んでいたものだという保障はないよ。","ENG":"But there's no guarantee you'll end up where you want to be.","TWN":"但是就算變強或者成長，也沒辦法保證那個結果是自身所希望的樣子。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"오히려 그렇지 않은 경우가 더 많지.","JPN":"むしろ、そうでない場合が多い。","ENG":"If anything, the opposite is often true.","TWN":"反而出現意料之外的情況比較多一些。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003040","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 누군가는 자신의 운명과 숙명에......","JPN":"だからある人は自分の運命や宿命に……","ENG":"So some people wish to fetter their own fate and destiny...","TWN":"所以有些人會對自己的命運和宿命……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003040","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"혹은 변치 않길 바라는 타인에게 족쇄를 채우려 들기도 하지.","JPN":"あるいは、変わらないでほしい誰かに足かせをはめようとする。","ENG":"Or those of others whom they wish would not change.","TWN":"或者給不願改變的其他人戴上枷鎖。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111043","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"왜 이런 따분한 얘기를 하냐고?","JPN":"なぜこんなくだらないことを言うのかって？","ENG":"What's with all this boring rambling, you ask?","TWN":"不明白為什麼要講這種枯燥的故事？"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"간단해, 네 숙명에 채워져 있던 구속구가 부서지기 직전이거든.","JPN":"簡単だよ。あなたの宿命につけられていた拘束具が壊れる直前なんだ。","ENG":"It's simple. The fetters on your destiny are about to break.","TWN":"很簡單，因為加在你宿命上的拘束器即將破碎。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"물론 클리포트 인자를 사용하기 시작한 시점에서 이미 금이 가 있었고, 언젠가는 부서질 예정이었어.","JPN":"確かにクリフォト・ファクターを使用し始めた時点ですでにひびが入っていたし、いずれは壊れる予定だった。","ENG":"It was already cracked when you started using the Qliphoth Factor. It was bound to break eventually.","TWN":"只要使用逆卡巴拉因子就會產生裂痕，然後終有一天會破碎。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만...... 지금은 시기가 너무 일러.","JPN":"でも……まだ時期が早い。","ENG":"But... It's too early now.","TWN":"但……現在時機尚早。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};